from collections import defaultdict
from typing import List

def solve(nums: List[int], queries: List[List[int]]) -> List[int]:
    ans = []
    for l, r, threshold in queries:
        freq = defaultdict(int)
        max_freq = -1
        candidate = -1
        for num in nums[l:r+1]:
            freq[num] += 1
        for num, count in freq.items():
            if count >= threshold:
                if count > max_freq:
                    max_freq = count
                    candidate = num
                elif count == max_freq and num < candidate:
                    candidate = num
        ans.append(candidate)
    return ans
